#include <stdio.h>
#include <string.h>
#include <stdbool.h>

#define MAXN 16

int n;
char s[MAXN];
bool pal[MAXN][MAXN];
char path[MAXN][MAXN];
int pathLen;
char results[5000][MAXN*2]; // enough for all partitions
int resCnt;

void dfs(int pos) {
    if (pos == n) {
        // build one line
        char line[256] = "";
        for (int i = 0; i < pathLen; ++i) {
            strcat(line, path[i]);
            if (i + 1 < pathLen) strcat(line, " ");
        }
        strcpy(results[resCnt++], line);
        return;
    }
    for (int end = pos; end < n; ++end) {
        if (pal[pos][end]) {
            int len = end - pos + 1;
            strncpy(path[pathLen], s + pos, len);
            path[pathLen][len] = '\0';
            ++pathLen;
            dfs(end + 1);
            --pathLen;
        }
    }
}

int cmpStr(const void *a, const void *b) {
    return strcmp((const char *)a, (const char *)b);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        scanf("%s", s);
        n = strlen(s);
        // palindrome table
        for (int i = 0; i < n; ++i) {
            for (int j = i; j < n; ++j) {
                bool ok = true;
                for (int l = i, r = j; l < r; ++l, --r) {
                    if (s[l] != s[r]) { ok = false; break; }
                }
                pal[i][j] = ok;
            }
        }
        resCnt = 0; pathLen = 0;
        dfs(0);
        qsort(results, resCnt, sizeof(results[0]), cmpStr);
        printf("%d\n", resCnt);
        for (int i = 0; i < resCnt; ++i) {
            printf("%s\n", results[i]);
        }
    }
    return 0;
}

