using namespace std;

void backtrack(int pos, const string &s, const vector<vector<bool>> &pal, vector<string> &cur, vector<vector<string>> &all) {
    int n = s.size();
    if (pos == n) {
        all.push_back(cur);
        return;
    }
    for (int end = pos; end < n; ++end) {
        if (pal[pos][end]) {
            cur.push_back(s.substr(pos, end - pos + 1));
            backtrack(end + 1, s, pal, cur, all);
            cur.pop_back();
        }
    }
}

