import java.io.*;
import java.util.*;

public class Main {
    static List<List<String>> all;
    static boolean[][] pal;
    static String s;
    static int n;

    static void dfs(int pos, List<String> cur) {
        if (pos == n) {
            all.add(new ArrayList<>(cur));
            return;
        }
        for (int end = pos; end < n; ++end) {
            if (pal[pos][end]) {
                cur.add(s.substring(pos, end + 1));
                dfs(end + 1, cur);
                cur.remove(cur.size() - 1);
            }
        }
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            s = br.readLine().trim();
            n = s.length();
            pal = new boolean[n][n];
            for (int i = 0; i < n; ++i) {
                for (int j = i; j < n; ++j) {
                    boolean ok = true;
                    for (int l = i, r = j; l < r; ++l, --r) {
                        if (s.charAt(l) != s.charAt(r)) { ok = false; break; }
                    }
                    pal[i][j] = ok;
                }
            }
            all = new ArrayList<>();
            dfs(0, new ArrayList<>());
            // sort lexicographically
            all.sort((a, b) -> {
                int m = Math.min(a.size(), b.size());
                for (int i = 0; i < m; ++i) {
                    int cmp = a.get(i).compareTo(b.get(i));
                    if (cmp != 0) return cmp;
                }
                return Integer.compare(a.size(), b.size());
            });
            out.append(all.size()).append('\n');
            for (List<String> part : all) {
                for (int i = 0; i < part.size(); ++i) {
                    if (i > 0) out.append(' ');
                    out.append(part.get(i));
                }
                out.append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

