import sys

def build_pal(s):
    n = len(s)
    pal = [[False]*n for _ in range(n)]
    for i in range(n):
        for j in range(i, n):
            ok = True
            l, r = i, j
            while l < r:
                if s[l] != s[r]:
                    ok = False
                    break
                l += 1
                r -= 1
            pal[i][j] = ok
    return pal

def backtrack(pos, s, pal, cur, res):
    n = len(s)
    if pos == n:
        res.append(cur.copy())
        return
    for end in range(pos, n):
        if pal[pos][end]:
            cur.append(s[pos:end+1])
            backtrack(end+1, s, pal, cur, res)
            cur.pop()

def solve():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    t = int(data[0])
    out_lines = []
    idx = 1
    for _ in range(t):
        s = data[idx].strip()
        idx += 1
        pal = build_pal(s)
        partitions = []
        backtrack(0, s, pal, [], partitions)
        partitions.sort()
        out_lines.append(str(len(partitions)))
        for p in partitions:
            out_lines.append(' '.join(p))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

