const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let t = Number(input[0] || 0);
let line = 1;
let output = [];
function buildPal(s) {
  const n = s.length;
  const pal = Array.from({ length: n }, () => Array(n).fill(false));
  for (let i = 0; i < n; ++i) {
    for (let j = i; j < n; ++j) {
      let ok = true;
      for (let l = i, r = j; l < r; ++l, --r) {
        if (s[l] !== s[r]) { ok = false; break; }
      }
      pal[i][j] = ok;
    }
  }
  return pal;
}
function dfs(pos, s, pal, cur, res) {
  const n = s.length;
  if (pos === n) {
    res.push(cur.slice());
    return;
  }
  for (let end = pos; end < n; ++end) {
    if (pal[pos][end]) {
      cur.push(s.substring(pos, end + 1));
      dfs(end + 1, s, pal, cur, res);
      cur.pop();
    }
  }
}
for (let caseIdx = 0; caseIdx < t; ++caseIdx) {
  const s = (input[line++] || '').trim();
  const pal = buildPal(s);
  const parts = [];
  dfs(0, s, pal, [], parts);
  parts.sort((a, b) => {
    const m = Math.min(a.length, b.length);
    for (let i = 0; i < m; ++i) {
      if (a[i] < b[i]) return -1;
      if (a[i] > b[i]) return 1;
    }
    return a.length - b.length;
  });
  output.push(String(parts.length));
  for (const p of parts) {
    output.push(p.join(' '));
  }
}
